const filterButtons=document.querySelectorAll(".filters button"),projects=document.querySelectorAll(".project-card");filterButtons.forEach(t=>{t.addEventListener("click",()=>{filterButtons.forEach(t=>t.classList.remove("active-filter")),t.classList.add("active-filter");const e=t.getAttribute("data-filter");projects.forEach(t=>{const r=t.getAttribute("data-category");"all"===e||r===e?t.classList.remove("hidden"):t.classList.add("hidden")})})});